const e=JSON.parse(`[{"q":"Viruses are considered as living organisms because they","options":["Can crystallize","Have cellular structure","Can reproduce inside host","Have metabolism"],"answer":2,"explanation":"Viruses are considered living because they can reproduce, but only inside a living host cell using host machinery."},{"q":"TMV (Tobacco Mosaic Virus) was crystallized by","options":["D.J. Ivanowski","W.M. Stanley","Beijerinck","Pasteur"],"answer":1,"explanation":"W.M. Stanley crystallized TMV in 1935 and showed it was a nucleoprotein. He received Nobel Prize for this work."},{"q":"The genetic material in HIV is","options":["Single stranded DNA","Double stranded DNA","Single stranded RNA","Double stranded RNA"],"answer":2,"explanation":"HIV is a retrovirus containing single stranded RNA as its genetic material. It uses reverse transcriptase to convert RNA to DNA."},{"q":"Bacteriophage was discovered by","options":["Twort and D'Herelle","Stanley","Ivanowski","Beijerinck"],"answer":0,"explanation":"Bacteriophage was independently discovered by Frederick Twort in 1915 and Felix d'Herelle in 1917."},{"q":"Viruses that infect bacteria are called","options":["Bacteriophage","Viroid","Prion","Retrovirus"],"answer":0,"explanation":"Bacteriophages (phages) are viruses that specifically infect bacteria. They inject their DNA into bacterial cells."},{"q":"The protein coat of virus is called","options":["Capsomere","Capsid","Envelope","Nucleocapsid"],"answer":1,"explanation":"The protein coat surrounding the nucleic acid of a virus is called capsid. It is made up of protein subunits called capsomeres."},{"q":"Which of the following disease is caused by virus?","options":["Cholera","Typhoid","Tuberculosis","AIDS"],"answer":3,"explanation":"AIDS is caused by HIV (Human Immunodeficiency Virus). Cholera, Typhoid and TB are caused by bacteria."},{"q":"Tobacco mosaic virus contains","options":["DNA only","RNA only","Both DNA and RNA","Neither DNA nor RNA"],"answer":1,"explanation":"Tobacco Mosaic Virus (TMV) contains only single stranded RNA as its genetic material, no DNA."},{"q":"Virus was first discovered by","options":["Stanley","Ivanowski","Beijerinck","Pasteur"],"answer":1,"explanation":"D.J. Ivanowski first discovered viruses in 1892 while studying tobacco mosaic disease. He found the causative agent passed through bacterial filters."},{"q":"Which of the following is a retrovirus?","options":["TMV","T4 phage","HIV","Adenovirus"],"answer":2,"explanation":"HIV is a retrovirus. Retroviruses contain RNA and use reverse transcriptase enzyme to make DNA from RNA."},{"q":"Prions are","options":["Small RNA without protein coat","Infectious proteins without nucleic acid","DNA viruses","RNA viruses"],"answer":1,"explanation":"Prions are infectious proteins without any nucleic acid. They cause diseases like mad cow disease and Creutzfeldt-Jakob disease."},{"q":"Viroids are","options":["Small RNA without protein coat","Infectious proteins","Small DNA virus","Defective virus"],"answer":0,"explanation":"Viroids are the smallest infectious agents consisting of small circular RNA without any protein coat. They cause plant diseases."},{"q":"The shape of TMV is","options":["Spherical","Helical","Cubical","Complex"],"answer":1,"explanation":"TMV (Tobacco Mosaic Virus) has a helical (rod-like) shape. The RNA is wound in a helix surrounded by protein capsomeres."},{"q":"AIDS is caused by","options":["Bacteria","Fungus","Protozoa","Virus"],"answer":3,"explanation":"AIDS (Acquired Immunodeficiency Syndrome) is caused by HIV (Human Immunodeficiency Virus), a retrovirus."},{"q":"Which of the following is the smallest virus?","options":["TMV","Parvovirus","Adenovirus","Poxvirus"],"answer":1,"explanation":"Parvovirus is the smallest known virus with a diameter of about 18-26 nm. Poxvirus is the largest animal virus."},{"q":"The nucleic acid present in bacteriophage is","options":["RNA only","DNA only","Both DNA and RNA","Neither"],"answer":1,"explanation":"Bacteriophage T4 contains double stranded DNA as its genetic material."},{"q":"Reverse transcriptase enzyme is found in","options":["Bacteriophage","TMV","Retrovirus","Adenovirus"],"answer":2,"explanation":"Reverse transcriptase is found in retroviruses like HIV. It converts RNA into DNA (reverse of normal transcription)."},{"q":"Which of the following is a plant disease caused by virus?","options":["Late blight","Loose smut","Mosaic disease","Tikka disease"],"answer":2,"explanation":"Mosaic disease of tobacco, tomato, and other plants is caused by viruses like TMV. The others are fungal diseases."},{"q":"The lytic cycle of bacteriophage involves","options":["Integration of viral DNA into host chromosome","Destruction of host cell","Dormancy of viral DNA","Slow release of virions"],"answer":1,"explanation":"In the lytic cycle, the virus replicates inside the host cell and causes its destruction (lysis) to release new virions."},{"q":"Virus contains","options":["Only nucleic acid","Only protein","Nucleic acid and protein","Cell organelles"],"answer":2,"explanation":"Viruses are made of nucleic acid (DNA or RNA) surrounded by a protein coat (capsid). They have no cell organelles."},{"q":"Which of the following has no cell wall?","options":["Bacteria","Virus","Fungi","Algae"],"answer":1,"explanation":"Viruses do not have a cell wall. They have a protein coat called capsid. They are not true cells at all."},{"q":"Foot and mouth disease in animals is caused by","options":["Bacteria","Fungus","Virus","Prion"],"answer":2,"explanation":"Foot and mouth disease in cattle and other cloven-hoofed animals is caused by a picornavirus (RNA virus)."},{"q":"Influenza is caused by","options":["Bacteria","Virus","Fungi","Protozoa"],"answer":1,"explanation":"Influenza (flu) is caused by Influenza virus. It is an RNA virus that causes respiratory infections."},{"q":"Which of the following acts as genetic material in most viruses?","options":["DNA only","RNA only","Either DNA or RNA","Both DNA and RNA simultaneously"],"answer":2,"explanation":"Viruses contain either DNA or RNA as genetic material, never both. DNA viruses include adenovirus, RNA viruses include TMV and HIV."},{"q":"The protein subunits of the capsid are called","options":["Capsid","Capsomeres","Nucleocapsid","Virion"],"answer":1,"explanation":"Capsomeres are the individual protein subunits that assemble to form the capsid (protein coat) of a virus."},{"q":"Lysogenic cycle differs from lytic cycle because in lysogenic cycle","options":["Host cell is immediately destroyed","Viral DNA integrates into host chromosome","Virus replicates rapidly","Host cell produces new viruses immediately"],"answer":1,"explanation":"In lysogenic cycle, viral DNA integrates into host chromosome as prophage and remains dormant. In lytic cycle, the host cell is immediately destroyed."},{"q":"Mumps is caused by","options":["Bacteria","Virus","Fungi","Worm"],"answer":1,"explanation":"Mumps is caused by Paramyxovirus. It causes swelling of the parotid salivary glands."},{"q":"Which of the following viruses causes cancer?","options":["TMV","Oncovirus","Bacteriophage","Adenovirus"],"answer":1,"explanation":"Oncoviruses are tumor-causing viruses. Examples include Human Papillomavirus (cervical cancer) and Hepatitis B virus (liver cancer)."},{"q":"Dengue fever is caused by","options":["Bacteria","Protozoa","Virus","Fungi"],"answer":2,"explanation":"Dengue fever is caused by Dengue virus transmitted by Aedes mosquito. It is a flavivirus containing single stranded RNA."},{"q":"T4 bacteriophage has","options":["Helical symmetry","Icosahedral symmetry","Complex symmetry","Spherical symmetry"],"answer":2,"explanation":"T4 bacteriophage has complex symmetry with an icosahedral head and a helical tail — neither purely helical nor purely icosahedral."},{"q":"Viruses are considered non-living because they","options":["Can reproduce","Lack cell structure and independent metabolism","Have nucleic acid","Can cause disease"],"answer":1,"explanation":"Viruses are considered non-living because they lack cellular structure, cannot metabolize independently, and can be crystallized like non-living matter."},{"q":"Which disease is caused by retrovirus?","options":["Influenza","Hepatitis B","AIDS","Rabies"],"answer":2,"explanation":"AIDS is caused by HIV which is a retrovirus. Retroviruses use reverse transcriptase to convert their RNA genome into DNA."},{"q":"Polio is caused by","options":["Bacteria","Virus","Protozoa","Fungi"],"answer":1,"explanation":"Polio (Poliomyelitis) is caused by Poliovirus, an RNA virus that attacks the nervous system and can cause paralysis."},{"q":"Which of the following is true about viruses?","options":["They have both DNA and RNA","They can grow outside host cell","They are obligate intracellular parasites","They have their own ribosomes"],"answer":2,"explanation":"Viruses are obligate intracellular parasites — they can only replicate inside a living host cell using the host's machinery."},{"q":"Hepatitis B is caused by","options":["RNA virus","DNA virus","Prion","Bacteria"],"answer":1,"explanation":"Hepatitis B is caused by Hepatitis B virus (HBV) which is a DNA virus. Hepatitis C is caused by an RNA virus."},{"q":"The largest virus is","options":["TMV","Bacteriophage","Poxvirus","Adenovirus"],"answer":2,"explanation":"Poxvirus (e.g., Smallpox virus) is the largest animal virus visible under light microscope. It can be up to 450nm."},{"q":"Smallpox is caused by","options":["Bacteria","Virus","Fungi","Protozoa"],"answer":1,"explanation":"Smallpox is caused by Variola virus (Poxvirus). It has been eradicated globally through vaccination."},{"q":"HIV infects which cells?","options":["Red blood cells","T-helper lymphocytes","B lymphocytes","Platelets"],"answer":1,"explanation":"HIV specifically targets and destroys CD4+ T-helper lymphocytes (T4 cells), weakening the immune system and leading to AIDS."},{"q":"Which of the following is an RNA virus?","options":["Adenovirus","Herpes virus","Poxvirus","HIV"],"answer":3,"explanation":"HIV is an RNA virus (retrovirus). Adenovirus, Herpes virus and Poxvirus are all DNA viruses."},{"q":"Rabies is caused by","options":["Bacteria","Virus","Protozoa","Fungi"],"answer":1,"explanation":"Rabies is caused by Rabies virus (Lyssavirus), a bullet-shaped RNA virus transmitted through the bite of infected animals."},{"q":"Which enzyme is used by HIV to integrate into host genome?","options":["Reverse transcriptase only","Integrase only","Both reverse transcriptase and integrase","Protease only"],"answer":2,"explanation":"HIV uses reverse transcriptase to convert its RNA to DNA, then integrase to integrate the viral DNA into the host chromosome."},{"q":"Measles is caused by","options":["Bacteria","Virus","Fungi","Protozoa"],"answer":1,"explanation":"Measles is caused by Measles virus (Morbillivirus), a paramyxovirus. It causes fever, rash and respiratory symptoms."},{"q":"The term virus was coined by","options":["Ivanowski","Pasteur","Beijerinck","Stanley"],"answer":2,"explanation":"Martinus Beijerinck coined the term \\"virus\\" (meaning poison in Latin) in 1898 after his experiments with tobacco mosaic disease."},{"q":"Chickenpox is caused by","options":["Bacteria","Fungus","Virus","Protozoa"],"answer":2,"explanation":"Chickenpox is caused by Varicella-Zoster virus (VZV), a DNA virus belonging to the Herpesviridae family."}]`);export{e as default};
